public int countGoodStrings(int minLength, int maxLength, int oneGroup, int zeroGroup) {
    int mod = 1000000007;
    int maxCount = maxLength / oneGroup + maxLength / zeroGroup;

    long[] dp = new long[maxCount + 1];
    dp[0] = 1;

    for (int i = 1; i <= maxCount; i++)
        dp[i] = (dp[i - 1] * (i % oneGroup == 0 || i % zeroGroup == 0 ? 1 : 0)) % mod;

    long ans = 0;
    for (int i = 0; i <= maxCount; i++) {
        ans = (ans + dp[minLength / oneGroup + minLength / zeroGroup - i]
               - ((minLength - 1) / oneGroup + (minLength - 1) / zeroGroup - i < 0 ? 0
               : dp[(minLength - 1) / oneGroup + (minLength - 1) / zeroGroup - i])) % mod;
    }

    return (int) ans;
}
```

